    },
    {
      "id": "D2",
      "content": "主要画面の応答時間目標を通信込みで1.2秒以内とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D3",
      "content": "本番リリースの目標時期を当初予定の9月末から2026年10月15日に変更する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D4",
      "content": "週次定例会議を毎週水曜日10時から1時間枠で開催し、各部署から最低1名参加とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D5",
      "content": "データ移行は第1フェーズでマスタ系のみを新システムへ移行し、トランザクション履歴は当面旧システム参照とする方針で進める",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D6",
      "content": "検証環境は現行6台構成をベースに一度倍増させてから冗長構成分を3台削った縮小構成で用意する方針とする",
      "decided_by": "沼田 賢一"
    },
    {
      "id": "D7",
      "content": "旧システムで途中変更されているコード体系については読み替えテーブルを作成して対応する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D8",
      "content": "認証およびマスタ配信の共通基盤はサクラ商事株式会社の基盤との共同利用（第3案）で進める",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D9",
      "content": "共通基盤共同利用に伴う費用按分方法はサクラ商事側への回答書の中で先方に提案・相談する方針とする",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D10",
      "content": "ベンダー比較の結果、ハギワラ技研とツヅキシステムを候補から外し、コマツバ・ソリューションズを前提に社内稟議を進める",
      "decided_by": "郡司 明久"
    },
    {
      "id": "D11",
      "content": "テスト工程構成として単体・結合・システム・受入に加え、移行テストと負荷テストを別立てで実施する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D12",
      "content": "負荷テストの合格基準は主要画面の応答時間1.2秒以内という目標値をピーク負荷時にも満たすこととし、測定点は社内ネットワーク側で明記する",
      "decided_by": "白鳥 千夏"
    },
    {
      "id": "D13",
      "content": "負荷テスト専用の実行環境を検証環境とは別に本番相当の縮小構成で立てる",
      "decided_by": "沼田 賢一"
    },
    {
      "id": "D14",
      "content": "現行システムのテストケースはそのまま流用せず、棚卸しして生存・廃棄・要修正の三区分に整理した上で利用する",
      "decided_by": "白鳥 千夏"
    },
    {
      "id": "D15",
      "content": "ユーザー権限ロールは新規設計せず現行ロール定義を流用し、ロール整理は稼働後の運用改善として別途実施する",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D16",
      "content": "システム障害発生時の一次受け窓口を情報システム部から品質保証部（QA）に変更し、QAが一次切り分け後に必要に応じて情報システム部へエスカレーションする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D17",
      "content": "移行方式は拠点を複数グループに分けて順次切り替える段階移行方式（B案）とし、全拠点一括や新旧並行稼働案は採用しない",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D18",
      "content": "拠点切替作業は原則として土曜深夜に実施し、日曜日を予備日とする",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D19",
      "content": "現場向けのシステム切替説明は拠点別に説明会の場を設けて実施し、口頭の伝達に頼らない",
      "decided_by": "桐生 遥"
    },
    {
      "id": "D20",
      "content": "移行リハーサルの手順書作成担当を品質保証部から情報システム部（沼田 賢一）に変更し、完成後に品質保証部がレビューする",
      "decided_by": "桐生 遥"
    }
  ],
